    def complete(self, prompt: str) -> LLMResult:
        ...

class MockLLMClient:
    def complete(self, prompt: str) -> LLMResult:
        latency_ms=random.randint(2000, 5000)
        time.sleep(latency_ms / 1000)

        if random.random() < 0.3:
            raise ValueError("Simulated LLM failure")
        
        return LLMResult(
            text=f"Echo: {prompt}",
            model="mock-llm",
            latency_ms=latency_ms
        )

